// In the real workflow this calls an LLM with a system prompt that defines Mrs Maggie's tone.
// Here we emit a deterministic example so the demo can run end-to-end with no credentials.
const events = ($json.events || []).map(e => `- ${e.time} ${e.title}`).join('\n');
const weather = $json.weather ? `${$json.weather.summary}, high ${$json.weather.high_c}°C` : 'no weather data';
const body = [
  'Good morning. Here is your briefing.',
  '',
  `Today: ${weather}.`,
  '',
  'On the calendar:',
  events || '- nothing scheduled',
  '',
  '— Mrs Maggie'
].join('\n');
return [{ json: { message: body } }];
